class Solution {
public:
    int minChanges(vector<int>& nums, int k) {
        int n = nums.size();
        vector<int> prefix_xor(n + 1);
        for (int i = 0; i < n; i++) {
            prefix_xor[i + 1] = prefix_xor[i] ^ nums[i];
        }
        int count[2048] = {0};
        int same = 0;
        for (int i = 0; i < k; i++) {
            int xor = prefix_xor[i + k] ^ prefix_xor[i];
            count[xor]++;
            if (xor == 0) same++;
        }
        int max_same = same;
        for (int i = k; i < n; i++) {
            int old_xor = prefix_xor[i] ^ prefix_xor[i - k];
            count[old_xor]--;
            if (old_xor == 0) same--;
            int new_xor = prefix_xor[i + 1] ^ prefix_xor[i + 1 - k];
            count[new_xor]++;
            if (new_xor == 0) same++;
            max_same = max(max_same, same);
        }
        return n - max_same;
    }
};
```
